// assets
import { DiamondIcon, ScanIcon, WifiIcon, ZapIcon } from "lucide-react";

const steps = [
  {
    id: 1,
    icon: DiamondIcon,
    iconBg: "bg-teal-300",
    title: "User Journey Map",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    id: 2,
    icon: ZapIcon,
    iconBg: "bg-orange-300",
    title: "Digital Wireframe",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    id: 3,
    icon: WifiIcon,
    iconBg: "bg-sky-300",
    title: "Clickable Prototype",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    id: 4,
    icon: ScanIcon,
    iconBg: "bg-violet-300",
    title: "Visual Design",
    description: "Better a diamond with a flaw than a pebble without one."
  }
];

//  ------------------------------ | PROCESS 1 | ------------------------------  //

export default function Process1() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14 flex flex-col gap-3">
          <p className="text-yellow-500 text-lg uppercase tracking-widest">
            Process
          </p>
          <h2 className="text-foreground">How We Work</h2>
          <p className="text-muted-foreground max-w-md mx-auto">
            This is a big one and i consider it one of the most important things
            for a designer to get right.
          </p>
        </div>

        {/* Steps */}
        {/* Icons row with connectors */}
        <div className="hidden lg:flex items-center mb-6">
          {steps.map((step) => {
            const Icon = step.icon;
            return (
              <div
                key={step.id}
                className="flex items-center flex-1 last:flex-none"
              >
                <div
                  className={`${step.iconBg} rounded-2xl p-4 inline-flex shrink-0`}
                >
                  <Icon className="size-7 text-white" strokeWidth={1.5} />
                </div>
              </div>
            );
          })}
        </div>

        {/* Text row below icons */}
        <div className="grid grid-cols-12 gap-6">
          {steps.map((step) => {
            const Icon = step.icon;
            return (
              <div
                key={step.id}
                className="col-span-12 sm:col-span-6 lg:col-span-3 flex flex-col gap-4"
              >
                {/* Icon visible only on mobile/tablet */}
                <div
                  className={`${step.iconBg} rounded-2xl p-4 inline-flex shrink-0 lg:hidden`}
                >
                  <Icon className="size-15 text-white" strokeWidth={1.5} />
                </div>
                <div className="flex flex-col gap-2">
                  <h5 className="text-foreground font-bold">
                    {step.id}. {step.title}
                  </h5>
                  <p className="text-muted-foreground text-md">
                    {step.description}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}
